code = """import pandas as pd
import json

# Load data from previous query results
cases = pd.DataFrame(var_call_9WSKvCOLynPlFqyAVy3H86Im)
accounts = pd.DataFrame(var_call_oqA9yhaiIafaHBUWpfLMMnQ9)

# Normalize IDs by stripping leading '#' and whitespace
def norm_id(x):
    if pd.isna(x):
        return x
    return str(x).strip().lstrip('#').strip()

cases['accountid_norm'] = cases['accountid'].apply(norm_id)
accounts['Id_norm'] = accounts['Id'].apply(norm_id)

# Parse datetimes
cases['createddate_parsed'] = pd.to_datetime(cases['createddate'], errors='coerce')
cases['closeddate_parsed'] = pd.to_datetime(cases['closeddate'], errors='coerce')

# Compute closure time in hours
cases['closure_hours'] = (cases['closeddate_parsed'] - cases['createddate_parsed']).dt.total_seconds() / 3600.0

# Merge with accounts on normalized id
merged = cases.merge(accounts, left_on='accountid_norm', right_on='Id_norm', how='left')

# Drop rows without state or without closure_hours
merged = merged[merged['ShippingState'].notna() & merged['closure_hours'].notna()]

# Trim state whitespace
merged['ShippingState'] = merged['ShippingState'].astype(str).str.strip()

# Group by state and compute average closure hours
state_stats = merged.groupby('ShippingState', dropna=True)['closure_hours'].mean().reset_index()

# If no data, return empty
if state_stats.shape[0] == 0:
    result = None
else:
    # Find state with minimum average closure time
    state_stats = state_stats.sort_values(['closure_hours', 'ShippingState'], ascending=[True, True])
    best_state = state_stats.iloc[0]['ShippingState']
    # Ensure two-letter uppercase
    best_state = str(best_state).upper()
    result = best_state

print("__RESULT__:")
print(json.dumps(result))"""

